import React from 'react';
import JobCard from './JobCard';

const JobList = ({ jobs, variant, onSelectJob }) => {
    return (
        <div style={{ 
            display: 'flex', 
            flexDirection: 'row',     // Mengubah ke horizontal
            flexWrap: 'wrap',         // Agar bisa turun ke bawah jika layar sempit
            gap: '20px', 
            justifyContent: 'center'  // Posisi kartu di tengah
        }}>
            {jobs.map(job => (
                <div key={job.id} style={{ flex: '0 1 300px' }}> {/* Memberikan lebar tetap per kartu */}
                    <JobCard 
                        job={job} 
                        isFull={variant === 'full'} 
                        onClick={() => onSelectJob && onSelectJob(job)}
                    />
                </div>
            ))}
        </div>
    );
};
export default JobList;
